package com.hogaria.controller; import com.hogaria.dto.*; import com.hogaria.service.TransactionService; import jakarta.validation.Valid; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/transactions") public class TransactionController { private final TransactionService service; private final com.hogaria.security.CurrentUserResolver resolver; public TransactionController(TransactionService s, com.hogaria.security.CurrentUserResolver r){this.service=s;this.resolver=r;} @PostMapping public TransactionResponse create(@Valid @RequestBody TransactionCreateRequest request,@RequestHeader("X-User-Id") String userId){ return service.create(request,resolver.parse(userId)); }}
